// Extract all moments and build a single structured item for GPT
const clips = $('4. WayinVideo — Get Moments Results').item.json.data?.clips || [];

if (clips.length === 0) {
  throw new Error('No moments found — try a different Section Search Query or verify the video is publicly accessible.');
}

// Sort clips by start time — chronological order for timestamps
const sortedClips = clips.sort((a, b) => (a.begin_ms || 0) - (b.begin_ms || 0));

// Build formatted moments list for GPT
const momentsForGPT = sortedClips.map((clip, index) => {
  const startMs = clip.begin_ms || 0;
  const minutes = Math.floor(startMs / 60000);
  const seconds = String(Math.floor((startMs % 60000) / 1000)).padStart(2, '0');
  const timestamp = `${minutes}:${seconds}`;
  return `Moment ${index + 1}: [${timestamp}] ${clip.title || 'Section'} — ${clip.desc || ''}`;
}).join('\n');

// Get form data
const videoTitle = $('1. Form — Video URL + Details').item.json['Video Title'];
const channelName = $('1. Form — Video URL + Details').item.json['Channel Name'];
const videoCategory = $('1. Form — Video URL + Details').item.json['Video Category'];
const targetAudience = $('1. Form — Video URL + Details').item.json['Target Audience'];
const videoUrl = $('1. Form — Video URL + Details').item.json['YouTube Video URL'];
const totalMoments = sortedClips.length;

// Calculate total video duration estimate
const lastClip = sortedClips[sortedClips.length - 1];
const totalMs = lastClip?.end_ms || lastClip?.begin_ms || 0;
const totalMinutes = Math.round(totalMs / 60000);

return [{
  json: {
    momentsForGPT,
    totalMoments,
    totalMinutes,
    videoTitle,
    channelName,
    videoCategory,
    targetAudience,
    videoUrl
  }
}];

// Parse AI output into structured fields
const output = $input.first().json.output || '';

// Extract each section
const timestampsMatch = output.match(/FORMATTED_TIMESTAMPS:\s*([\s\S]*?)(?=\nVIDEO_DESCRIPTION_BLOCK:|$)/);
const descBlockMatch = output.match(/VIDEO_DESCRIPTION_BLOCK:\s*([\s\S]*?)(?=\nCOMMUNITY_POST:|$)/);
const communityPostMatch = output.match(/COMMUNITY_POST:\s*([\s\S]*?)(?=\nHASHTAGS:|$)/);
const hashtagsMatch = output.match(/HASHTAGS:\s*([\s\S]*?)(?=\nTOTAL_CHAPTERS:|$)/);
const totalChaptersMatch = output.match(/TOTAL_CHAPTERS:\s*([\d]+)/);

const formattedTimestamps = timestampsMatch ? timestampsMatch[1].trim() : '';
const videoDescriptionBlock = descBlockMatch ? descBlockMatch[1].trim() : '';
const communityPost = communityPostMatch ? communityPostMatch[1].trim() : '';
const hashtags = hashtagsMatch ? hashtagsMatch[1].trim() : '';
const totalChapters = totalChaptersMatch ? parseInt(totalChaptersMatch[1]) : 0;

if (!formattedTimestamps) {
  throw new Error('Could not parse timestamps from AI output. Check the AI prompt format.');
}

// Get video data from step 7
const videoData = $('7. Code — Collect + Sort All Moments').item.json;

return [{
  json: {
    formattedTimestamps,
    videoDescriptionBlock,
    communityPost,
    hashtags,
    totalChapters,
    videoTitle: videoData.videoTitle,
    channelName: videoData.channelName,
    videoCategory: videoData.videoCategory,
    videoUrl: videoData.videoUrl,
    totalMoments: videoData.totalMoments,
    totalMinutes: videoData.totalMinutes
  }
}];
